import{_ as e,o,c as a,an as t}from"./chunks/framework.D5fFzH9V.js";const u=JSON.parse('{"title":"📝 Information Security and Privacy Policy","description":"Policy defining how Syslifters protects information security and personal data.","frontmatter":{"title":"📝 Information Security and Privacy Policy","description":"Policy defining how Syslifters protects information security and personal data."},"headers":[],"relativePath":"organization/information-security-policy.md","filePath":"organization/information-security-policy.md"}'),n={name:"organization/information-security-policy.md"};function r(s,i,l,c,d,p){return o(),a("div",null,[...i[0]||(i[0]=[t('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /organization/information-security-policy.md for this page in Markdown format</div><h1 id="📝-information-security-and-privacy-policy" tabindex="-1">📝 Information Security and Privacy Policy <a class="header-anchor" href="#📝-information-security-and-privacy-policy" aria-label="Permalink to &quot;📝 Information Security and Privacy Policy&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>This Information Security Policy establishes the principles and responsibilities for protecting the confidentiality, integrity, and availability of information assets, including personal information, handled by Syslifters GmbH. It ensures compliance with applicable data protection and privacy laws and supports the organization’s commitment to maintaining the trust of customers, employees, and partners.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This policy applies to all employees, contractors, and third parties who access or manage Syslifters’s information systems, networks, or data—whether stored digitally or physically.</p><h2 id="information-protection-principles" tabindex="-1">Information Protection Principles <a class="header-anchor" href="#information-protection-principles" aria-label="Permalink to &quot;Information Protection Principles&quot;">​</a></h2><ul><li>Confidentiality – Personal and sensitive data must be protected from unauthorized access, disclosure, or misuse.</li><li>Integrity – Information must be accurate, complete, and protected from unauthorized modification or destruction.</li><li>Availability – Information and systems must be accessible to authorized users as needed for business operations.</li></ul><h2 id="personal-information-protection" tabindex="-1">Personal Information Protection <a class="header-anchor" href="#personal-information-protection" aria-label="Permalink to &quot;Personal Information Protection&quot;">​</a></h2><ul><li>Personal data shall be collected, stored, processed, and transmitted only for legitimate business purposes and in accordance with applicable privacy regulations (e.g., GDPR, CCPA).</li><li>Technical and organizational safeguards—including encryption, access controls, secure authentication, and audit logging—must be implemented to protect personal information against loss, theft, or unauthorized disclosure.</li><li>Data minimization and retention principles shall be applied to ensure personal information is not kept longer than necessary.</li><li>Any suspected or confirmed security or privacy incident involving personal data must be reported immediately to the company&#39;s directors and managed according to the organization’s incident response procedures.</li></ul><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><p>All staff are required to adhere to this policy and to complete periodic information security and privacy training. The management is responsible for overseeing compliance, monitoring controls, and updating the policy as needed.</p><h2 id="policy-review" tabindex="-1">Policy Review <a class="header-anchor" href="#policy-review" aria-label="Permalink to &quot;Policy Review&quot;">​</a></h2><p>This policy will be reviewed annually or following significant organizational or regulatory changes.</p><p>Last reviewed: 13/04/2026</p>',15)])])}const y=e(n,[["render",r]]);export{u as __pageData,y as default};
